/* HELPERS                                                             */
/* ================================================================== */

const overall = (s) => Math.round(Object.values(s).reduce((a, b) => a + b, 0) / Object.values(s).length);
const initialsOf = (n) => n.split(" ").map((x) => x[0]).slice(0, 2).join("");
const levelOf = (xp) => Math.floor(xp / 500) + 1;
const pilarEsporte = (a) => overall(a.skills);
const pilarCorpo = (a) => Math.round(((a.wellbeing.sono + a.wellbeing.alimentacao + a.wellbeing.exercicio) / 3 / 7) * 100);
const pilarMente = (a) => Math.round(a.estudo.media * 10 * 0.5 + ENG[a.estudo.ingles] * 0.5);
const indiceIntegral = (a) => Math.round((pilarEsporte(a) + pilarCorpo(a) + pilarMente(a)) / 3);
const stageIndex = (age) => (age <= 15 ? 0 : age === 16 ? 1 : age === 17 ? 2 : 3);
const contactOpen = (age) => stageIndex(age) >= 1;
const tagInfo = { treino: { label: "Treino", emoji: "🏃", color: "#3b82f6" }, alimentacao: { label: "Alimentação", emoji: "🍎", color: "#22c55e" } };

const QUESTIONS = [
  { id: "q1", texto: "Como está sua confiança hoje?", dir: "pos" },
  { id: "q2", texto: "Está com medo de errar?", dir: "neg" },
  { id: "q3", texto: "Está motivado para treinar?", dir: "pos" },
  { id: "q4", texto: "Está preocupado com a opinião dos outros?", dir: "neg" },
];
const OPCOES = ["Nunca", "Raram.", "Às vezes", "Freq.", "Sempre"];
const RISCO_MAX = QUESTIONS.length * 4;
const calcularRisco = (r) => QUESTIONS.reduce((s, q) => s + (q.dir === "pos" ? 4 - (r[q.id] ?? 0) : (r[q.id] ?? 0)), 0);
const nivelRisco = (sc) => (sc <= 5 ? { label: "Baixo", cor: "#22c55e" } : sc <= 10 ? { label: "Médio", cor: "#f59e0b" } : { label: "Forte", cor: "#f87171" });
const confiancaDe = (sc) => Math.round((1 - sc / RISCO_MAX) * 100);
const comportamentosDe = (r) => {
  const o = [];
  if ((r.q2 ?? 0) >= 3) o.push({ n: "Medo de errar", s: "Treine sem cobrar perfeição. Errar faz parte." });
  if ((r.q4 ?? 0) >= 3) o.push({ n: "Comparação com os outros", s: "Compare-se com você de ontem, não com o colega." });
  if ((r.q1 ?? 4) <= 1) o.push({ n: "Baixa confiança", s: "Registre conquistas pequenas. Elas constroem confiança." });
  if ((r.q3 ?? 4) <= 1) o.push({ n: "Pouca motivação", s: "Defina um objetivo pequeno pro próximo treino." });
  return o;
};

