function Card({ children, className = "", style = {} }) { return <div className={`card ${className}`} style={style}>{children}</div>; }
function Avatar({ name, size = 44 }) { return <div className="avatar" style={{ width: size, height: size, fontSize: size * 0.36 }}>{initialsOf(name)}</div>; }
function LogoMark({ size = 34 }) {
  return <img src={LOGO_SRC} alt="Rumo à Bolsa" style={{ height: size, width: "auto", objectFit: "contain", display: "block" }} draggable={false} />;
}
function ActionButton({ label, done = "Feito", icon: Icon, className = "btn-accent w-full", style }) {
  const [clicked, setClicked] = useState(false);
  return (
    <button className={className} style={style} onClick={() => setClicked(true)}>
      {clicked ? (<><Check size={15} /> {done}</>) : (<>{Icon && <Icon size={15} />} {label}</>)}
    </button>
  );
}
function Ring({ value, color, label }) {
  const r = 26, c = 2 * Math.PI * r, off = c - (Math.max(0, Math.min(100, value)) / 100) * c;
  return (
    <div className="ring-wrap">
      <svg width="72" height="72" viewBox="0 0 72 72">
        <circle cx="36" cy="36" r={r} stroke="rgba(255,255,255,0.1)" strokeWidth="6" fill="none" />
        <circle cx="36" cy="36" r={r} stroke={color} strokeWidth="6" fill="none" strokeLinecap="round" strokeDasharray={c} strokeDashoffset={off} transform="rotate(-90 36 36)" />
        <text x="36" y="42" textAnchor="middle" fontSize="18" fontWeight="800" fill="#fff" fontFamily="Hanken Grotesk">{value}</text>
      </svg>
      <div className="ring-label">{label}</div>
    </div>
  );
}
function HabitRow({ icon, label, days, accent }) {
  const Icon = icon;
  return (
    <div>
      <div className="flex justify-between items-center text-xs mb-1"><span className="text-muted flex items-center gap-1.5"><Icon size={13} /> {label}</span><span className="text-white font-semibold">{days} de 7 dias</span></div>
      <div className="xpbar"><div className="xpfill" style={{ width: `${(days / 7) * 100}%`, background: accent }} /></div>
    </div>
  );
}
function CheckItem({ ok, label, value }) {
  return (
    <div className="vidrow">
      <div className="thumb" style={{ background: ok ? "#22c55e22" : "#f59e0b22", color: ok ? "#22c55e" : "#f59e0b" }}>{ok ? <Check size={15} /> : <Clock size={15} />}</div>
      <div className="flex-1 text-white text-sm">{label}</div>
      {value && <span className="pill" style={{ background: ok ? "#22c55e22" : "#f59e0b22", color: ok ? "#22c55e" : "#f59e0b" }}>{value}</span>}
    </div>
  );
}
function SkillRadar({ skills, accent }) {
  const data = Object.entries(skills).map(([k, v]) => ({ skill: k, value: v }));
  return (
    <ResponsiveContainer width="100%" height={240}>
      <RadarChart data={data} outerRadius="72%"><PolarGrid stroke="rgba(255,255,255,0.08)" /><PolarAngleAxis dataKey="skill" tick={{ fill: "#9aa4b2", fontSize: 11 }} /><Radar dataKey="value" stroke={accent} fill={accent} fillOpacity={0.35} /></RadarChart>
    </ResponsiveContainer>
  );
}
function EvolutionChart({ history, accent }) {
  return (
    <ResponsiveContainer width="100%" height={180}>
      <AreaChart data={history} margin={{ top: 8, right: 8, left: -22, bottom: 0 }}>
        <defs><linearGradient id="grad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={accent} stopOpacity={0.5} /><stop offset="100%" stopColor={accent} stopOpacity={0} /></linearGradient></defs>
        <XAxis dataKey="mes" tick={{ fill: "#9aa4b2", fontSize: 11 }} axisLine={false} tickLine={false} /><YAxis domain={[40, 100]} tick={{ fill: "#9aa4b2", fontSize: 11 }} axisLine={false} tickLine={false} />
        <Tooltip contentStyle={{ background: "#11161f", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: "#fff" }} /><Area type="monotone" dataKey="media" stroke={accent} strokeWidth={2.5} fill="url(#grad)" />
      </AreaChart>
    </ResponsiveContainer>
  );
}
function VideoRow({ v, action }) {
  return (
    <div className="vidrow"><div className="thumb"><Play size={16} /></div><div className="flex-1"><div className="text-white text-sm font-medium">{v.title}</div><div className="text-muted text-xs">{v.date}</div></div>
      {action ? action : v.status === "avaliado" ? <span className="pill" style={{ background: "#22c55e22", color: "#22c55e" }}><Check size={12} /> Nota {v.note}</span> : <span className="pill" style={{ background: "#f59e0b22", color: "#f59e0b" }}><Clock size={12} /> Aguardando</span>}
    </div>
  );
}

