const CODIGO_RESPONSAVEL = "4821";
function AgeGate({ athlete, onDone }) {
  const idade = athlete.age;
  const maior = idade >= 12;
  const [code, setCode] = useState("");
  const [erros, setErros] = useState(0);
  const bloqueado = erros >= 3;
  const verificar = () => { if (code === CODIGO_RESPONSAVEL) onDone(); else { setErros((e) => e + 1); setCode(""); } };
  return (
    <div className="login"><div className="loginbox">
      <div className="flex flex-col items-center mb-4">
        <div className="iconbox" style={{ width: 52, height: 52, borderRadius: 14, background: "#22c55e22", color: "#22c55e" }}><Shield size={26} /></div>
        <div className="brand mt-3" style={{ fontSize: 20 }}>Verificação de segurança</div>
        <div className="text-muted text-center" style={{ fontSize: 12, marginTop: 4 }}>Confirme a autorização para liberar o acesso.</div>
      </div>

      <div className="vidrow" style={{ marginBottom: 12 }}>
        <div className="thumb" style={{ background: "#22c55e22", color: "#22c55e" }}><FileCheck size={15} /></div>
        <div className="flex-1"><div className="text-white text-sm font-medium">{athlete.name}</div><div className="text-muted text-xs">Idade registrada pela escola: {idade} anos</div></div>
        <span className="pill" style={{ background: "#22c55e22", color: "#22c55e" }}><Check size={12} /> Verificada</span>
      </div>

      {maior ? (
        <>
          <div className="vidrow" style={{ background: "#22c55e1a" }}><div className="thumb" style={{ background: "#22c55e22", color: "#22c55e" }}><Check size={15} /></div><div className="flex-1 text-white text-sm">{idade} anos. Você pode usar o app normalmente.</div></div>
          <button className="btn-accent w-full mt-3" style={{ "--accent": BRAND }} onClick={onDone}>Entrar</button>
        </>
      ) : bloqueado ? (
        <div className="vidrow" style={{ background: "#f871711a" }}><div className="thumb" style={{ background: "#f8717122", color: "#f87171" }}><Lock size={15} /></div><div className="flex-1 text-white text-sm">Acesso bloqueado por tentativas. Fale com a coordenação do projeto para liberar.</div></div>
      ) : (
        <>
          <div className="vidrow" style={{ background: "#f59e0b1a", marginBottom: 10 }}><div className="thumb" style={{ background: "#f59e0b22", color: "#f59e0b" }}><Lock size={15} /></div><div className="flex-1 text-white text-sm">{idade} anos. Menores de 12 precisam do código de acesso do responsável para entrar.</div></div>
          <div className="text-muted text-xs mb-2">Enviamos um código de 6 dígitos ao responsável cadastrado (e-mail e WhatsApp). Peça o código a ele. Você não consegue gerar esse código sozinho.</div>
          <input className="field-input" inputMode="numeric" maxLength={6} placeholder="Código do responsável" value={code} onChange={(e) => setCode(e.target.value.replace(/\D/g, ""))} />
          {erros > 0 && <div className="text-xs" style={{ color: "#f87171", marginBottom: 8 }}>Código incorreto. Tentativas restantes: {3 - erros}.</div>}
          <button className="btn-accent w-full" style={{ "--accent": BRAND, opacity: code.length >= 4 ? 1 : 0.4 }} disabled={code.length < 4} onClick={verificar}>Verificar e entrar</button>
          <div className="text-muted text-center mt-3" style={{ fontSize: 11 }}>O código é gerado e enviado apenas ao responsável cadastrado.</div>
        </>
      )}
      <div className="text-muted text-center mt-3" style={{ fontSize: 11 }}>A idade vem do cadastro da escola. A partir de 12 anos o atleta entra normalmente. Abaixo disso, só com o código do responsável.</div>
    </div></div>
  );
}

function LoginScreen({ onLogin }) {
  const [sel, setSel] = useState("atleta");
  const role = LOGIN_ROLES.find((r) => r.id === sel);
  return (
    <div className="login"><div className="loginbox">
      <div className="flex flex-col items-center mb-5"><LogoMark size={56} /><div className="brand mt-3" style={{ fontSize: 24, letterSpacing: 1 }}>RUMO À BOLSA</div><div className="text-muted" style={{ fontSize: 11, letterSpacing: 2 }}>SUPERAÇÃO ESPORTIVA</div></div>
      <div className="text-muted text-xs mb-2">Entrar como</div>
      <div className="grid gap-2 mb-4">{LOGIN_ROLES.map((r) => { const Icon = r.icon, on = sel === r.id; return (<button key={r.id} onClick={() => setSel(r.id)} className="rolepick" style={{ borderColor: on ? BRAND : "rgba(255,255,255,0.1)", background: on ? `${BRAND}1f` : "rgba(255,255,255,0.02)" }}><div className="iconbox" style={{ background: on ? `${BRAND}33` : "rgba(255,255,255,0.06)", color: on ? "#9cc0ff" : "#9aa4b2", width: 38, height: 38 }}><Icon size={18} /></div><div className="flex-1 text-left"><div className="text-white text-sm font-semibold">{r.label}</div><div className="text-muted text-xs">{r.desc}</div></div>{on && <Check size={18} style={{ color: "#9cc0ff" }} />}</button>); })}</div>
      <input className="field-input" value={role.mail} readOnly /><input className="field-input" type="password" defaultValue="demo1234" placeholder="Senha" />
      <button className="btn-accent w-full mt-1" style={{ "--accent": BRAND }} onClick={() => onLogin(sel)}>Entrar</button>
    </div></div>
  );
}

/* ================================================================== */
/* CHAT                                                                */
/* ================================================================== */

function ChatScreen({ me, accent }) {
  const [convs, setConvs] = useState(CONVERSAS);
  const [selId, setSelId] = useState(CONVERSAS[0].id);
  const [mobileThread, setMobileThread] = useState(false);
  const [text, setText] = useState("");
  const endRef = useRef(null), foodRef = useRef(null), trainRef = useRef(null);
  const sel = convs.find((c) => c.id === selId) || convs[0];
  const meFirst = me.name.split(" ")[0];
  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [sel.msgs.length, selId]);
  const now = () => new Date().toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });
  const push = (extra) => setConvs((cs) => cs.map((c) => c.id === selId ? { ...c, msgs: [...c.msgs, { autor: meFirst, role: me.roleLabel, mine: true, time: now(), ...extra }] } : c));
  const sendText = () => { if (!text.trim()) return; push({ text: text.trim() }); setText(""); };
  const onFile = (e, tag) => { const f = e.target.files?.[0]; if (!f) return; const r = new FileReader(); r.onload = () => push({ image: r.result, tag, text: text.trim() || null }); r.readAsDataURL(f); setText(""); e.target.value = ""; };
  const openConv = (id) => { setSelId(id); setMobileThread(true); };
  const preview = (c) => { const m = c.msgs[c.msgs.length - 1]; return m.image || m.ph ? "📷 Foto" : m.text; };
  let lastData = null;
  return (
    <div className={`chatlayout ${mobileThread ? "viewing-thread" : ""}`}>
      <div className="convlist">
        <div className="text-muted" style={{ padding: "4px 8px 8px", fontWeight: 700, letterSpacing: 0.5, fontSize: 11 }}>CONVERSAS</div>
        {convs.map((c) => (
          <button key={c.id} className="convrow" onClick={() => openConv(c.id)} style={{ background: c.id === selId ? "rgba(255,255,255,0.05)" : "rgba(255,255,255,0.02)" }}>
            <div className="convicon" style={{ background: `${c.cor}33`, fontSize: 18 }}>{c.icon}</div>
            <div className="convmeta"><div className="convname">{c.nome}</div><div className="convprev">{preview(c)}</div></div>
            <div className="convright"><span className="text-muted" style={{ fontSize: 10 }}>{c.msgs[c.msgs.length - 1].time}</span>{c.naoLidas > 0 && <span className="unread" style={{ background: accent }}>{c.naoLidas}</span>}</div>
          </button>
        ))}
        <div className="text-muted text-center" style={{ fontSize: 10, marginTop: 8 }}>Conversas moderadas pelos professores e coordenação.</div>
      </div>

      <div className="convthread">
        <div className="threadhead">
          <button className="iconbtn threadback" onClick={() => setMobileThread(false)}><ArrowLeft size={16} /></button>
          <div className="convicon" style={{ background: `${sel.cor}33`, fontSize: 16, width: 36, height: 36 }}>{sel.icon}</div>
          <div className="flex-1"><div className="text-white text-sm font-semibold">{sel.nome}</div><div className="text-muted text-xs">{sel.sub}</div></div>
          <span className="pill" style={{ background: "#22c55e22", color: "#22c55e" }}><Shield size={12} /> Moderado</span>
        </div>
        {sel.pin && <div className="pinmsg"><Lock size={13} style={{ flexShrink: 0, marginTop: 1 }} /><span>{sel.pin}</span></div>}
        <div className="chatscroll" style={{ padding: "10px 14px" }}>
          {sel.msgs.map((m, idx) => {
            const mine = m.mine || m.autor === meFirst;
            const tag = m.tag || m.ph?.tag;
            const showData = m.data && m.data !== lastData; if (m.data) lastData = m.data;
            return (
              <React.Fragment key={idx}>
                {showData && <div className="datesep">{m.data}</div>}
                <div className={`msgrow ${mine ? "mine" : ""}`}>
                  {!mine && <div className="convicon" style={{ width: 30, height: 30, background: `${sel.cor}33`, fontSize: 12, color: "#e7ecf2", fontWeight: 700 }}>{initialsOf(m.autor)}</div>}
                  <div style={{ maxWidth: "80%" }}>
                    {!mine && <div className="msgauthor">{m.autor} · {m.role}</div>}
                    <div className="bubble" style={mine ? { background: accent, color: "#06090f" } : {}}>
                      {tag && <span className="tagchip" style={{ background: mine ? "rgba(0,0,0,0.12)" : `${tagInfo[tag].color}22`, color: mine ? "#06090f" : tagInfo[tag].color }}>{tagInfo[tag].emoji} {tagInfo[tag].label}</span>}
                      {m.image && <img src={m.image} alt="" className="msgimg" />}
                      {m.ph && <div className="photoph"><span style={{ fontSize: 34 }}>{m.ph.emoji}</span><span style={{ fontSize: 11, opacity: 0.8 }}>{m.ph.cap}</span></div>}
                      {m.text && <div style={{ marginTop: tag || m.image || m.ph ? 6 : 0 }}>{m.text}</div>}
                    </div>
                    <div className="msgtime" style={{ textAlign: mine ? "right" : "left" }}>{m.time}{mine && <span style={{ color: accent, marginLeft: 5 }}>✓✓</span>}</div>
                  </div>
                </div>
              </React.Fragment>
            );
          })}
          <div ref={endRef} />
        </div>
        <div className="chatinput">
          <input ref={foodRef} type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFile(e, "alimentacao")} /><input ref={trainRef} type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFile(e, "treino")} />
          <button className="attach" onClick={() => foodRef.current.click()} title="Foto da alimentação"><Apple size={18} /></button><button className="attach" onClick={() => trainRef.current.click()} title="Foto do treino"><Dumbbell size={18} /></button>
          <input className="chattext" placeholder={`Mensagem em ${sel.nome}...`} value={text} onChange={(e) => setText(e.target.value)} onKeyDown={(e) => e.key === "Enter" && sendText()} /><button className="sendbtn" style={{ background: accent }} onClick={sendText}><Send size={16} /></button>
        </div>
      </div>
    </div>
  );
}

