function Vitrine({ athlete }) {
  const sport = SPORTS[athlete.sport];
  return (
    <Card className="p-5" style={{ background: `linear-gradient(135deg, ${sport.accent}22, transparent)` }}>
      <div className="flex items-center justify-between mb-4"><div className="flex items-center gap-3"><Avatar name={athlete.name} size={52} /><div><div className="text-white font-bold text-lg leading-tight">{athlete.name}</div><div className="text-muted text-sm">{sport.emoji} {sport.label} · {athlete.position} · {athlete.age} anos</div></div></div><div className="text-right"><div className="bignum" style={{ color: sport.accent }}>{indiceIntegral(athlete)}</div><div className="text-muted text-xs">índice integral</div></div></div>
      <div className="grid grid-cols-2 gap-2 mb-3">{Object.entries(athlete.skills).map(([k, v]) => (<div key={k} className="flex items-center justify-between rounded-lg px-3 py-2" style={{ background: "rgba(255,255,255,0.04)" }}><span className="text-muted text-xs">{k}</span><span className="text-white text-sm font-semibold">{v}</span></div>))}</div>
      <div className="flex gap-2 mb-4 flex-wrap"><span className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}><BookOpen size={12} /> Escola {athlete.estudo.media.toFixed(1)}</span><span className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}><Languages size={12} /> Inglês {athlete.estudo.ingles}</span></div>
      <ActionButton icon={Upload} label="Montar meu vídeo de destaque" done="Vídeo em montagem" />
    </Card>
  );
}

