function CaminhoExterior({ athlete }) {
  const c = athlete.caminho.exterior, e = athlete.estudo.eng;
  const st = stageIndex(athlete.age);
  const checks = [
    { ok: c.ncaaReg, label: "Registro no NCAA Eligibility Center", value: c.ncaaReg ? "Feito" : "Pendente" },
    { ok: c.cursos >= 16, label: "16 cursos básicos concluídos", value: `${c.cursos}/16` },
    { ok: c.gpa >= GPA_MIN_D1, label: `GPA de núcleo ≥ ${GPA_MIN_D1} (Divisão I)`, value: c.gpa.toFixed(1) },
    { ok: e.duolingo >= e.alvo, label: "Inglês na meta da faculdade", value: `${e.duolingo} → ${e.alvo}` },
  ];
  return (
    <div className="grid gap-4">
      <Card className="p-4">
        <div className="card-title"><Compass size={15} /> Onde você está na jornada</div>
        <div className="timeline">{NCAA_STAGES.map((s, i) => (
          <div className="tlitem" key={i}>
            <div className="tlrail"><div className="tldot" style={{ background: i <= st ? "#22c55e" : "rgba(255,255,255,0.18)", boxShadow: i === st ? "0 0 0 4px #22c55e33" : "none" }} />{i < NCAA_STAGES.length - 1 && <div className="tlline" style={{ background: i < st ? "#22c55e" : "rgba(255,255,255,0.12)" }} />}</div>
            <div style={{ paddingBottom: 14 }}><div className="text-sm font-semibold" style={{ color: i === st ? "#22c55e" : "#e7ecf2" }}>{s.titulo}{i === st && " · você"}</div><div className="text-muted text-xs">{s.desc}</div></div>
          </div>
        ))}</div>
        <p className="text-muted text-xs mt-1">As datas seguem o ano escolar dos EUA (15 de junho após o 2º ano). A idade aqui é só uma referência.</p>
      </Card>

      <Card className="p-4">
        <div className="card-title"><FileCheck size={15} /> Elegibilidade NCAA</div>
        <div className="grid gap-2">{checks.map((c2, i) => <CheckItem key={i} {...c2} />)}</div>
        <p className="text-muted text-xs mt-3">Desde 2023 a NCAA não exige mais SAT nem ACT. O que conta é cursar os 16 núcleos e manter a GPA mínima.</p>
      </Card>

      <Card className="p-4">
        <div className="card-title"><Languages size={15} /> Inglês para o exterior</div>
        <div className="flex justify-between items-center text-xs mb-1"><span className="text-muted">Duolingo English Test</span><span className="text-white font-semibold">{e.duolingo} → meta {e.alvo}</span></div>
        <div className="xpbar"><div className="xpfill" style={{ width: `${Math.min(100, (e.duolingo / 160) * 100)}%`, background: "#3b82f6" }} /></div>
        <p className="text-muted text-xs mt-3">As faculdades pedem nota em teste (TOEFL, IELTS ou Duolingo). A faixa comum vai de ~105 a 130 no Duolingo, conforme a seletividade da escola.</p>
      </Card>

      <Card className="p-4">
        <div className="card-title"><Star size={15} /> Minha lista de faculdades-alvo</div>
        <div className="grid gap-2">{athlete.targets.map((t, i) => (<div key={i} className="vidrow"><div className="thumb" style={{ background: "#a855f722", color: "#a855f7" }}><Star size={15} /></div><div className="flex-1"><div className="text-white text-sm font-medium">{t.school}</div><div className="text-muted text-xs flex items-center gap-1"><MapPin size={11} /> {t.local} · {t.div}</div></div></div>))}</div>
        <p className="text-muted text-xs mt-3">Você monta sua lista e inicia o contato. Treinadores só podem responder a partir das datas da jornada acima.</p>
      </Card>

      <Vitrine athlete={athlete} />
    </div>
  );
}

function CaminhoBrasil({ athlete }) {
  const b = athlete.caminho.brasil;
  const checks = [
    { ok: b.federacao, label: "Filiado a uma federação da modalidade", value: b.federacao ? "Sim" : "Pendente" },
    { ok: b.resultado, label: "Resultado top 3 em competição nacional ou estudantil", value: b.resultado ? "Sim" : "Pendente" },
    { ok: athlete.age >= 14, label: "Idade a partir de 14 anos", value: `${athlete.age} anos` },
    { ok: athlete.estudo.media >= 6, label: "Matrícula e desempenho escolar em dia", value: athlete.estudo.media.toFixed(1) },
  ];
  return (
    <div className="grid gap-4">
      <Card className="p-4">
        <div className="card-title"><Award size={15} /> Bolsa Atleta (federal)</div>
        <div className="grid gap-2">{checks.map((c, i) => <CheckItem key={i} {...c} />)}</div>
        <p className="text-muted text-xs mt-3">É um auxílio mensal do Ministério do Esporte, não bolsa de faculdade. Categorias de base (14 a 19) e estudantil (14 a 20) exigem resultado em competição reconhecida.</p>
      </Card>

      <Card className="p-4">
        <div className="card-title"><GraduationCap size={15} /> Bolsa esportiva em universidade privada</div>
        <div className="flex gap-2 flex-wrap mb-3">{UNIS_BR.map((u) => (<span key={u} className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}>{u}</span>))}</div>
        <p className="text-muted text-sm">Cada universidade tem processo próprio de seleção esportiva. Os descontos vão de 50% a 100% da mensalidade, e você precisa manter o desempenho acadêmico para conservar a bolsa.</p>
      </Card>

      <Card className="p-4" style={{ background: "linear-gradient(135deg, #22c55e1a, transparent)" }}>
        <div className="card-title"><Target size={15} /> Por que começar pelo Brasil</div>
        <p className="text-muted text-sm">O caminho brasileiro é mais alcançável no curto prazo: depende de competir e pontuar, não de teste de inglês nem das datas de contato da NCAA. Bons resultados aqui também fortalecem seu vídeo e seu perfil para o exterior depois.</p>
      </Card>
    </div>
  );
}

function CaminhoScreen({ athlete }) {
  const [track, setTrack] = useState("brasil");
  return (
    <div className="grid gap-4">
      <div className="seg" style={{ width: "100%" }}>
        <button className="segbtn" style={{ flex: 1, background: track === "brasil" ? BRAND : "transparent", color: track === "brasil" ? "#fff" : "#9aa4b2" }} onClick={() => setTrack("brasil")}>🇧🇷 Brasil</button>
        <button className="segbtn" style={{ flex: 1, background: track === "exterior" ? BRAND : "transparent", color: track === "exterior" ? "#fff" : "#9aa4b2" }} onClick={() => setTrack("exterior")}>🌎 Exterior</button>
      </div>
      {track === "brasil" ? <CaminhoBrasil athlete={athlete} /> : <CaminhoExterior athlete={athlete} />}
    </div>
  );
}

