function AthleteHome({ athlete }) {
  const sport = SPORTS[athlete.sport];
  const lvl = levelOf(athlete.xp), xpInLevel = athlete.xp % 500;
  const pilares = [{ v: pilarCorpo(athlete), c: "#22c55e", l: "Corpo" }, { v: pilarMente(athlete), c: "#3b82f6", l: "Mente" }, { v: pilarEsporte(athlete), c: sport.accent, l: "Esporte" }];
  const menor = [...pilares].sort((a, b) => a.v - b.v)[0];
  return (
    <div className="grid gap-4">
      <Card className="p-5" style={{ background: `linear-gradient(135deg, ${sport.accent}26, transparent 70%)` }}>
        <div className="flex items-center gap-4"><Avatar name={athlete.name} size={58} /><div className="flex-1"><div className="text-white font-bold text-lg leading-tight">{athlete.name.split(" ")[0]}</div><div className="text-muted text-sm">{sport.emoji} {sport.label} · Nível {lvl}</div></div><div className="text-right"><div className="bignum-sm" style={{ color: sport.accent }}>{indiceIntegral(athlete)}</div><div className="text-muted text-xs">integral</div></div></div>
        <div className="flex justify-between text-xs mt-4 mb-1"><span className="text-muted">Nível {lvl}</span><span className="text-white font-semibold">{xpInLevel}/500 XP</span></div><div className="xpbar"><div className="xpfill" style={{ width: `${(xpInLevel / 500) * 100}%`, background: sport.accent }} /></div>
      </Card>
      <div className="dash2">
      <Card className="p-4"><div className="card-title"><Activity size={15} /> A pessoa que joga</div><div className="flex justify-around">{pilares.map((p) => <Ring key={p.l} value={p.v} color={p.c} label={p.l} />)}</div></Card>
      <Card className="p-4"><div className="card-title"><Sparkles size={15} /> Sua formação integral</div><SkillRadar skills={formacaoSkills(athlete)} accent={sport.accent} /><p className="text-muted text-xs mt-1">Aqui você não é só um jogador. O projeto te desenvolve por inteiro: técnica, corpo, cabeça, convívio, emoção e hábitos. Não precisa ser craque para evoluir.</p></Card>
      <Card className="p-4"><div className="card-title"><Target size={15} /> Foco da semana</div><p className="text-muted text-sm">Seu pilar mais baixo agora é <b style={{ color: menor.c }}>{menor.l}</b>.{menor.l === "Corpo" && " Cuidar do sono e da alimentação destrava o resto."}{menor.l === "Mente" && " Avançar no inglês e na escola te aproxima da bolsa."}{menor.l === "Esporte" && " Um treino focado no seu fundamento mais fraco já ajuda."}</p></Card>
      </div>
    </div>
  );
}

const MOODS = [["Cansado", "😴"], ["Ok", "🙂"], ["Bem", "😃"], ["Ótimo", "🔥"]];
const CORPO_PERGUNTAS = [
  { id: "sono", titulo: "Como foi sua noite de sono?", icon: Moon, ops: ["Ruim", "Ok", "Boa", "Ótima"] },
  { id: "alim", titulo: "Como você comeu hoje?", icon: Apple, ops: ["Mal", "Razoável", "Bem", "Muito bem"] },
  { id: "mov", titulo: "Como foi sua movimentação?", icon: Activity, ops: ["Parado", "Pouco", "Ativo", "Muito ativo"] },
];
function CorpoRegistro({ onBack }) {
  const [r, setR] = useState({});
  const [salvo, setSalvo] = useState(false);
  const completo = CORPO_PERGUNTAS.every((p) => r[p.id] != null);
  return (
    <div className="grid gap-4">
      <button className="btn-ghost" style={{ width: "fit-content" }} onClick={onBack}><ArrowLeft size={15} /> Voltar</button>
      <div className="text-muted text-sm">Registre como foi seu dia. Leva 10 segundos e ajuda a cuidar de você por inteiro.</div>
      {CORPO_PERGUNTAS.map((p) => { const Icon = p.icon; return (
        <Card key={p.id} className="p-4">
          <div className="card-title"><Icon size={15} /> {p.titulo}</div>
          <div className="flex gap-2">{p.ops.map((o, idx) => (<button key={o} onClick={() => { setR((s) => ({ ...s, [p.id]: idx })); setSalvo(false); }} className="scalebtn" style={{ borderColor: r[p.id] === idx ? BRAND : "rgba(255,255,255,0.1)", background: r[p.id] === idx ? "#2f6fe01a" : "transparent", color: r[p.id] === idx ? "#fff" : "#9aa4b2" }}>{o}</button>))}</div>
        </Card>
      ); })}
      <button className="btn-accent w-full" style={{ "--accent": "#22c55e", opacity: completo ? 1 : 0.4 }} disabled={!completo} onClick={() => setSalvo(true)}>{salvo ? "Registro salvo ✓" : "Salvar registro do dia"}</button>
      {salvo && (<Card className="p-4"><div className="text-white text-sm font-semibold mb-1">Registro de hoje salvo 💚</div><div className="text-muted text-sm">Sono: {CORPO_PERGUNTAS[0].ops[r.sono]} · Comida: {CORPO_PERGUNTAS[1].ops[r.alim]} · Movimento: {CORPO_PERGUNTAS[2].ops[r.mov]}.</div><p className="text-muted text-xs mt-2">Isso conta pra sua constância da semana. Sem dieta, sem peso, só o cuidado do dia a dia.</p></Card>)}
    </div>
  );
}

function AthletePessoa({ athlete }) {
  const [mood, setMood] = useState(2);
  const [resp, setResp] = useState({});
  const [analisado, setAnalisado] = useState(false);
  const [regOpen, setRegOpen] = useState(false);
  const w = athlete.wellbeing, e = athlete.estudo;
  const completo = QUESTIONS.every((q) => resp[q.id] != null);
  const score = calcularRisco(resp), nivel = nivelRisco(score), comps = comportamentosDe(resp);
  if (regOpen) return <CorpoRegistro onBack={() => setRegOpen(false)} />;
  return (
    <div className="grid gap-4">
      <Card className="p-4"><div className="card-title"><Smile size={15} /> Como você está hoje?</div><div className="flex gap-2">{MOODS.map((m, i) => (<button key={i} onClick={() => setMood(i)} className="moodbtn" style={{ borderColor: mood === i ? "#22c55e" : "rgba(255,255,255,0.1)", background: mood === i ? "#22c55e1a" : "transparent" }}><span style={{ fontSize: 22 }}>{m[1]}</span><span className="text-muted" style={{ fontSize: 11 }}>{m[0]}</span></button>))}</div></Card>

      <Card className="p-4">
        <div className="card-title"><Shield size={15} /> Check-in: autossabotagem</div>
        {QUESTIONS.map((q, i) => (
          <div key={q.id} className="mb-3">
            <div className="text-white text-sm mb-2">{i + 1}. {q.texto}</div>
            <div className="flex gap-1">{OPCOES.map((o, idx) => (<button key={o} onClick={() => { setResp((p) => ({ ...p, [q.id]: idx })); setAnalisado(false); }} className="scalebtn" style={{ borderColor: resp[q.id] === idx ? BRAND : "rgba(255,255,255,0.1)", background: resp[q.id] === idx ? "#2f6fe01a" : "transparent", color: resp[q.id] === idx ? "#fff" : "#9aa4b2" }}>{o}</button>))}</div>
          </div>
        ))}
        <button className="btn-accent w-full" style={{ "--accent": "#6366f1", opacity: completo ? 1 : 0.4 }} disabled={!completo} onClick={() => setAnalisado(true)}>Analisar</button>
        {analisado && (
          <div className="mt-3">
            <div className="flex items-center justify-between rounded-lg px-3 py-2" style={{ background: `${nivel.cor}1a` }}><span className="text-white text-sm font-semibold">Confiança: {confiancaDe(score)}%</span><span className="pill" style={{ background: `${nivel.cor}22`, color: nivel.cor }}>{nivel.label} sinal</span></div>
            {comps.length > 0 ? (<div className="grid gap-2 mt-2">{comps.map((c, i) => (<div key={i} className="rounded-lg px-3 py-2" style={{ background: "rgba(255,255,255,0.04)" }}><div className="text-white text-sm font-medium">{c.n}</div><div className="text-muted text-xs">{c.s}</div></div>))}</div>) : <div className="text-muted text-sm mt-2">Nenhum sinal forte hoje. Mandou bem.</div>}
            <p className="text-muted text-xs mt-2">É uma reflexão de como você está hoje, não um diagnóstico.</p>
          </div>
        )}
      </Card>

      <Card className="p-4"><div className="card-title"><Heart size={15} /> Corpo</div><div className="grid gap-3"><HabitRow icon={Moon} label="Dormiu bem" days={w.sono} accent="#22c55e" /><HabitRow icon={Apple} label="Comeu bem" days={w.alimentacao} accent="#22c55e" /><HabitRow icon={Activity} label="Se movimentou" days={w.exercicio} accent="#22c55e" /></div><button className="btn-ghost w-full mt-3" onClick={() => setRegOpen(true)}><Activity size={15} /> Registrar meu dia (sono, comida, movimento)</button><p className="text-muted text-xs mt-2">Constância leve vale mais que extremo. Sem dieta nem meta de peso.</p></Card>
      <Card className="p-4"><div className="card-title"><BookOpen size={15} /> Mente e estudo</div><div className="flex items-center justify-between rounded-lg px-3 py-2 mb-3" style={{ background: "rgba(255,255,255,0.04)" }}><span className="text-muted text-sm">Média na escola</span><span className="text-white font-semibold">{e.media.toFixed(1)}</span></div><div className="flex justify-between items-center text-xs mb-1"><span className="text-muted flex items-center gap-1.5"><Languages size={13} /> Inglês (Duolingo)</span><span className="text-white font-semibold">{e.eng.duolingo} → meta {e.eng.alvo}</span></div><div className="xpbar"><div className="xpfill" style={{ width: `${Math.min(100, (e.eng.duolingo / 160) * 100)}%`, background: "#3b82f6" }} /></div><p className="text-muted text-xs mt-3">Veja o caminho completo na aba Caminho.</p></Card>
    </div>
  );
}

function RoutineCard() {
  return (
    <Card className="p-4">
      <div className="card-title"><Clock size={15} /> Rotina da semana</div>
      <div className="grid gap-2">{ROUTINE.map((r, i) => (<div key={i} className="vidrow"><div className="daychip">{r.dia}</div><div className="flex-1"><div className="text-white text-sm font-medium">{r.tipo}</div><div className="text-muted text-xs flex items-center gap-1"><Clock size={11} /> {r.hora} · <MapPin size={11} /> {r.local}</div></div></div>))}</div>
    </Card>
  );
}

function AttendancePoll({ accent }) {
  const [status, setStatus] = useState(null);
  const base = { vou: 11, talvez: 3, nao: 2 };
  const confirmados = base.vou + (status === "vou" ? 1 : 0);
  const opts = [["vou", "Vou", "#22c55e"], ["talvez", "Talvez", "#f59e0b"], ["nao", "Não vou", "#f87171"]];
  return (
    <Card className="p-4">
      <div className="card-title"><Users size={15} /> Presença no próximo treino</div>
      <div className="flex items-center justify-between mb-3">
        <div><div className="text-white text-sm font-medium">{NEXT_TRAINING.tipo} · {NEXT_TRAINING.dia} {NEXT_TRAINING.data}</div><div className="text-muted text-xs flex items-center gap-1"><Clock size={11} /> {NEXT_TRAINING.hora} · <MapPin size={11} /> {NEXT_TRAINING.local}</div></div>
        <span className="pill" style={{ background: `${accent}22`, color: accent }}>{confirmados} confirmados</span>
      </div>
      <div className="flex gap-2">{opts.map(([k, l, c]) => (<button key={k} onClick={() => setStatus(k)} className="pollbtn" style={{ borderColor: status === k ? c : "rgba(255,255,255,0.1)", background: status === k ? `${c}1a` : "transparent", color: status === k ? c : "#9aa4b2" }}>{l}</button>))}</div>
      <p className="text-muted text-xs mt-3">Confirme aqui, não no WhatsApp. O professor vê quem vai em tempo real.</p>
    </Card>
  );
}

function CoachTraining() {
  const counts = RSVP_SEED.reduce((a, r) => { a[r.s] = (a[r.s] || 0) + 1; return a; }, {});
  const label = { vou: "Vai", talvez: "Talvez", nao: "Não vai", sem: "Sem resposta" };
  const color = { vou: "#22c55e", talvez: "#f59e0b", nao: "#f87171", sem: "#7b8696" };
  return (
    <div className="grid gap-4">
      <RoutineCard />
      <Card className="p-4">
        <div className="card-title"><Users size={15} /> Presença · {NEXT_TRAINING.tipo} ({NEXT_TRAINING.dia} {NEXT_TRAINING.data})</div>
        <div className="flex gap-2 mb-3 flex-wrap">{["vou", "talvez", "nao", "sem"].map((k) => (<span key={k} className="pill" style={{ background: `${color[k]}22`, color: color[k] }}>{counts[k] || 0} {label[k]}</span>))}</div>
        <div className="grid gap-1">{RSVP_SEED.map((r, i) => (<div key={i} className="vidrow"><Avatar name={r.name} size={32} /><div className="flex-1 text-white text-sm">{r.name}</div><span className="pill" style={{ background: `${color[r.s]}22`, color: color[r.s] }}>{label[r.s]}</span></div>))}</div>
        <p className="text-muted text-xs mt-3">Substitui a chamada no WhatsApp. Fica tudo registrado no app.</p>
      </Card>
    </div>
  );
}

function AthleteTraining({ athlete }) {
  const sport = SPORTS[athlete.sport];
  return (
    <div className="grid gap-4">
      <RoutineCard />
      <AttendancePoll accent={sport.accent} />
      <Card className="p-4"><div className="card-title"><Target size={15} /> Fundamentos</div><SkillRadar skills={athlete.skills} accent={sport.accent} /></Card>
      <Card className="p-4"><div className="card-title"><Video size={15} /> Meus vídeos</div><div className="grid gap-2">{athlete.videos.map((v) => <VideoRow key={v.id} v={v} />)}<ActionButton icon={Upload} label="Enviar novo vídeo" done="Vídeo enviado" className="btn-accent w-full mt-1" /></div></Card>
      <Card className="p-4"><div className="card-title"><Zap size={15} /> Desafios</div><div className="grid gap-2">{[["Treino de " + Object.entries(athlete.skills).sort((a, b) => a[1] - b[1])[0][0], 120, false], ["Dormir bem por 5 dias", 80, false], ["Estudar inglês 3x na semana", 100, true]].map(([t, xp, done], i) => (<div key={i} className="vidrow"><div className="thumb" style={{ background: done ? "#22c55e22" : "rgba(255,255,255,0.07)", color: done ? "#22c55e" : "#cfd6e0" }}>{done ? <Check size={16} /> : <Target size={15} />}</div><div className="flex-1 text-white text-sm">{t}</div><span className="pill" style={{ background: `${sport.accent}22`, color: sport.accent }}>+{xp} XP</span></div>))}</div><p className="text-muted text-xs mt-2">Cuidar do corpo e estudar também dão XP.</p></Card>
      <Card className="p-4"><div className="card-title"><TrendingUp size={15} /> Evolução no esporte</div><EvolutionChart history={athlete.history} accent={sport.accent} /></Card>
    </div>
  );
}

