function ParentChild({ athlete }) {
  const sport = SPORTS[athlete.sport], w = athlete.wellbeing;
  const nome = athlete.name.split(" ")[0];
  return (
    <div className="grid gap-4">
      <Card className="p-5 flex items-center gap-4"><Avatar name={athlete.name} size={56} /><div className="flex-1"><div className="text-white font-bold text-lg">{athlete.name}</div><div className="text-muted text-sm">{sport.emoji} {sport.label} · {athlete.age} anos</div></div><div className="text-right"><div className="bignum-sm" style={{ color: sport.accent }}>{indiceIntegral(athlete)}</div><div className="text-muted text-xs">integral</div></div></Card>

      <Card className="p-4" style={{ background: "linear-gradient(135deg, #22c55e1a, transparent)" , borderColor: "rgba(34,197,94,0.3)" }}>
        <div className="card-title"><Sparkles size={15} /> O foco do projeto</div>
        <p className="text-muted text-sm leading-relaxed">Isto não é uma escolinha de futsal. É um projeto de <b className="text-white">formação integral</b> através do futsal. {nome} se desenvolve no social, no emocional, nos hábitos, no cognitivo e no convívio, não só na bola. {nome} não precisa ser craque para crescer aqui.</p>
      </Card>

      <Card className="p-4"><div className="card-title"><Activity size={15} /> {nome} por inteiro</div><SkillRadar skills={formacaoSkills(athlete)} accent={sport.accent} /><p className="text-muted text-xs mt-1">Veja como {nome} evolui em todas as áreas, não apenas na técnica.</p></Card>

      <Card className="p-4"><div className="card-title"><Heart size={15} /> Hábitos da semana</div><div className="grid gap-3"><HabitRow icon={Moon} label="Dormiu bem" days={w.sono} accent="#22c55e" /><HabitRow icon={Apple} label="Comeu bem" days={w.alimentacao} accent="#22c55e" /><HabitRow icon={Activity} label="Se movimentou" days={w.exercicio} accent="#22c55e" /></div><p className="text-muted text-xs mt-3">Sono e alimentação são onde a família mais faz diferença.</p></Card>
    </div>
  );
}
function ParentPrivacy({ athlete }) {
  const nome = athlete.name.split(" ")[0];
  const garantias = [
    "Tratamento sempre no melhor interesse de " + nome + " (art. 14 da LGPD).",
    "Consentimento específico e em destaque, dado por você como responsável.",
    "Linguagem simples sobre quais dados coletamos e para quê.",
    "Você pode revogar o consentimento a qualquer momento.",
  ];
  return (
    <div className="grid gap-4">
      <Card className="p-4" style={{ borderColor: "rgba(34,197,94,0.3)" }}>
        <div className="card-title"><Shield size={15} /> Privacidade e consentimento (LGPD)</div>
        <div className="grid gap-2">{garantias.map((g, i) => (<div key={i} className="vidrow"><div className="thumb" style={{ background: "#22c55e22", color: "#22c55e" }}><Check size={15} /></div><div className="flex-1 text-white text-sm">{g}</div></div>))}</div>
      </Card>
      <Card className="p-4"><div className="card-title"><FileCheck size={15} /> Dados que coletamos</div><div className="flex gap-2 flex-wrap">{["Vídeos de treino", "Fotos do chat", "Hábitos (sono, alimentação)", "Desempenho escolar", "Avaliações do professor"].map((d) => (<span key={d} className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}>{d}</span>))}</div></Card>
      <div className="grid gap-2"><details className="policy"><summary>Ver política completa</summary><p className="text-muted text-sm" style={{ marginTop: 8 }}>Coletamos apenas os dados necessários para acompanhar a formação do atleta. O responsável pode pedir acesso, correção ou exclusão a qualquer momento. Dados de menores seguem o art. 14 da LGPD, com consentimento específico do responsável. Nada é vendido nem compartilhado para fins comerciais.</p></details><ActionButton label="Revogar consentimento" done="Consentimento revogado" className="btn-ghost w-full" style={{ color: "#f87171", borderColor: "rgba(248,113,113,0.3)" }} /></div>
    </div>
  );
}
function CoachAthletes({ athletes, onPick }) {
  return (<Card className="p-3"><div className="card-title"><Users size={15} /> Meus atletas</div><div className="grid gap-1">{athletes.map((a) => { const pend = a.videos.filter((v) => v.status === "pendente").length; return (<button key={a.id} onClick={() => onPick(a.id)} className="athlete-pick"><Avatar name={a.name} size={38} /><div className="flex-1 text-left"><div className="text-white text-sm font-medium leading-tight">{a.name}</div><div className="text-muted text-xs">{SPORTS[a.sport].emoji} {SPORTS[a.sport].label} · integral {indiceIntegral(a)}</div></div>{pend > 0 && <span className="dot" style={{ background: "#f59e0b" }}>{pend}</span>}<ChevronRight size={16} className="text-muted" /></button>); })}</div></Card>);
}
function CoachEvaluate({ athletes, selId }) {
  const athlete = athletes.find((a) => a.id === selId) || athletes[0];
  const sport = SPORTS[athlete.sport];
  const nome = athlete.name.split(" ")[0];
  const [tipo, setTipo] = useState("semanal");
  const [salvo, setSalvo] = useState({ semanal: false, mensal: false });
  const [sem, setSem] = useState({ desempenho: 7, empenho: 8, obs: "" });
  const [men, setMen] = useState({ tecnico: 7, convivio: 8, comprometimento: 7, obs: "" });

  const sld = (label, value, on) => (
    <div className="mb-3"><div className="flex justify-between text-xs mb-1"><span className="text-muted">{label}</span><span className="text-white font-semibold">{value}</span></div><input type="range" min="0" max="10" value={value} onChange={(e) => on(Number(e.target.value))} className="range" style={{ accentColor: sport.accent }} /></div>
  );

  return (
    <div className="grid gap-4">
      <Card className="p-4 flex items-center gap-3"><Avatar name={athlete.name} size={44} /><div className="flex-1"><div className="text-white font-semibold">{athlete.name}</div><div className="text-muted text-xs">{sport.emoji} {sport.label} · {athlete.age} anos</div></div></Card>

      <div className="seg" style={{ width: "100%" }}>
        <button className="segbtn" style={{ flex: 1, background: tipo === "semanal" ? BRAND : "transparent", color: tipo === "semanal" ? "#fff" : "#9aa4b2" }} onClick={() => setTipo("semanal")}>Avaliação semanal</button>
        <button className="segbtn" style={{ flex: 1, background: tipo === "mensal" ? BRAND : "transparent", color: tipo === "mensal" ? "#fff" : "#9aa4b2" }} onClick={() => setTipo("mensal")}>Avaliação mensal</button>
      </div>

      {tipo === "semanal" ? (
        <Card className="p-4">
          <div className="card-title"><Clock size={15} /> Como foi a semana de {nome}</div>
          {sld("Desempenho geral na semana", sem.desempenho, (v) => { setSem((s) => ({ ...s, desempenho: v })); setSalvo((x) => ({ ...x, semanal: false })); })}
          {sld("Empenho e atitude", sem.empenho, (v) => { setSem((s) => ({ ...s, empenho: v })); setSalvo((x) => ({ ...x, semanal: false })); })}
          <textarea className="field-input" rows={2} placeholder="Observação da semana (opcional)" value={sem.obs} onChange={(e) => setSem((s) => ({ ...s, obs: e.target.value }))} style={{ resize: "none", marginBottom: 10 }} />
          <button className="btn-accent w-full" style={{ "--accent": sport.accent }} onClick={() => setSalvo((x) => ({ ...x, semanal: true }))}>{salvo.semanal ? "Avaliação da semana salva ✓" : "Salvar avaliação da semana"}</button>
        </Card>
      ) : (
        <Card className="p-4">
          <div className="card-title"><BarChart3 size={15} /> Avaliação do mês de {nome}</div>
          {sld("Evolução técnica e tática", men.tecnico, (v) => { setMen((s) => ({ ...s, tecnico: v })); setSalvo((x) => ({ ...x, mensal: false })); })}
          {sld("Comportamento e convívio", men.convivio, (v) => { setMen((s) => ({ ...s, convivio: v })); setSalvo((x) => ({ ...x, mensal: false })); })}
          {sld("Comprometimento", men.comprometimento, (v) => { setMen((s) => ({ ...s, comprometimento: v })); setSalvo((x) => ({ ...x, mensal: false })); })}
          <textarea className="field-input" rows={2} placeholder="Parecer do mês (opcional)" value={men.obs} onChange={(e) => setMen((s) => ({ ...s, obs: e.target.value }))} style={{ resize: "none", marginBottom: 10 }} />
          <button className="btn-accent w-full" style={{ "--accent": sport.accent }} onClick={() => setSalvo((x) => ({ ...x, mensal: true }))}>{salvo.mensal ? "Avaliação do mês salva ✓" : "Salvar avaliação do mês"}</button>
        </Card>
      )}

      <Card className="p-4"><div className="card-title"><Activity size={15} /> Lembrete</div><p className="text-muted text-sm">Aqui você não avalia fundamento por fundamento. São só duas avaliações: uma rápida toda semana e uma mais completa por mês. {nome} é mais que a nota técnica, considere também o convívio e o empenho.</p></Card>
    </div>
  );
}
function RecruiterSearch({ athletes }) {
  const [openId, setOpenId] = useState(null);
  const open = athletes.find((a) => a.id === openId);
  if (open) return (
    <div className="grid gap-4"><button className="btn-ghost" style={{ width: "fit-content" }} onClick={() => setOpenId(null)}><ArrowLeft size={15} /> Voltar</button><Vitrine athlete={open} /><Card className="p-4"><div className="card-title"><TrendingUp size={15} /> Evolução no esporte</div><EvolutionChart history={open.history} accent={SPORTS[open.sport].accent} />
      {contactOpen(open.age)
        ? <ActionButton icon={Heart} label="Demonstrar interesse" done="Interesse registrado" className="btn-accent w-full mt-3" style={{ "--accent": SPORTS[open.sport].accent }} />
        : <div className="lockednote"><Lock size={14} /> Contato liberado a partir de 15 de junho após o 2º ano (~16 anos). {open.name.split(" ")[0]} tem {open.age}.</div>}
    </Card></div>
  );
  return (
    <div className="grid gap-3">
      <Card className="p-3 flex items-center gap-2"><Search size={16} className="text-muted" /><span className="text-muted text-sm">Talentos de todos os esportes</span><span className="pill ml-auto" style={{ background: "rgba(255,255,255,0.06)", color: "#9aa4b2" }}>{athletes.length}</span></Card>
      <div className="grid gap-3" style={{ gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))" }}>{athletes.map((a) => { const sport = SPORTS[a.sport]; return (<Card key={a.id} className="p-4 athlete-card" style={{ "--accent": sport.accent }}><div className="flex items-center justify-between mb-3"><Avatar name={a.name} size={42} /><div className="bignum-sm" style={{ color: sport.accent }}>{indiceIntegral(a)}</div></div><div className="text-white font-semibold leading-tight text-sm">{a.name}</div><div className="text-muted text-xs mb-2">{sport.emoji} {a.position} · {a.age}a</div><div className="text-muted text-xs mb-3 flex items-center gap-1">{contactOpen(a.age) ? <><Check size={11} style={{ color: "#22c55e" }} /> contato liberado</> : <><Lock size={11} /> contato bloqueado</>}</div><button className="btn-ghost w-full" onClick={() => setOpenId(a.id)}>Ver perfil <ChevronRight size={14} /></button></Card>); })}</div>
    </div>
  );
}

