function CoachPanel() {
  const totalAlunos = FAIXAS.reduce((a, f) => a + f.alunos, 0);
  const retMedia = Math.round(FAIXAS.reduce((a, f) => a + f.retencao * f.alunos, 0) / totalAlunos);
  const intMedia = Math.round(FAIXAS.reduce((a, f) => a + f.integral * f.alunos, 0) / totalAlunos);
  return (
    <div className="grid gap-4">
      <Card className="p-4" style={{ background: "linear-gradient(135deg, #22c55e22, transparent 70%)" }}>
        <div className="text-muted text-xs">Projeto</div>
        <div className="text-white font-bold text-lg">{PROJETO.nome}</div>
        <div className="text-muted text-sm">{PROJETO.alunos} alunos por semana · {PROJETO.cidades.length} cidades</div>
        <div className="flex gap-2 mt-3 flex-wrap">{PROJETO.cidades.map((c) => (<span key={c} className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}><MapPin size={11} /> {c}</span>))}</div>
      </Card>

      <div className="grid grid-cols-2 gap-3">
        <Card className="p-3"><Activity size={18} style={{ color: "#22c55e" }} /><div className="bignum-sm text-white mt-1">{intMedia}</div><div className="text-muted text-xs">Formação integral média</div></Card>
        <Card className="p-3"><Heart size={18} style={{ color: retMedia >= 80 ? "#22c55e" : "#f59e0b" }} /><div className="bignum-sm text-white mt-1">{retMedia}%</div><div className="text-muted text-xs">Permanência média</div></Card>
      </div>

      <div className="dash2">
      <Card className="p-4">
        <div className="card-title"><BarChart3 size={15} /> Por faixa etária</div>
        <div className="grid gap-2">
          {FAIXAS.map((f, i) => (
            <div key={i} className="faixarow">
              <div className="flex items-center justify-between mb-2"><span className="text-white text-sm font-medium">{f.faixa}</span><span className="text-muted text-xs">{f.alunos} alunos</span></div>
              <div className="flex gap-3">
                <div className="flex-1"><div className="text-muted" style={{ fontSize: 10, marginBottom: 3 }}>Formação integral · {f.integral}</div><div className="xpbar"><div className="xpfill" style={{ width: `${f.integral}%`, background: "#22c55e" }} /></div></div>
                <div className="flex-1"><div className="text-muted" style={{ fontSize: 10, marginBottom: 3 }}>Permanência · {f.retencao}%</div><div className="xpbar"><div className="xpfill" style={{ width: `${f.retencao}%`, background: f.retencao >= 80 ? "#22c55e" : "#f59e0b" }} /></div></div>
              </div>
            </div>
          ))}
        </div>
        <p className="text-muted text-xs mt-3">A permanência cai nas faixas mais velhas. É onde a evasão mais aparece.</p>
      </Card>

      <Card className="p-4" style={{ borderColor: "rgba(245,158,11,0.3)" }}>
        <div className="card-title"><Target size={15} /> Principal causa de evasão</div>
        <p className="text-muted text-sm leading-relaxed">As famílias muitas vezes não entendem que isto é um projeto de formação integral, e não uma escolinha de futsal. Pais acham que o filho "não é bom de bola" e o tiram do projeto, mesmo ele estando evoluindo como pessoa.</p>
        <ActionButton label="Enviar aos responsáveis o foco do projeto" done="Mensagem enviada aos responsáveis" className="btn-accent w-full mt-3" style={{ "--accent": BRAND }} />
        <ActionButton label="Agendar reunião com as famílias" done="Reunião sugerida à coordenação" className="btn-ghost w-full mt-2" />
      </Card>
      </div>

      <Card className="p-3"><div className="card-title" style={{ marginBottom: 8 }}><Users size={15} /> Equipe</div><div className="flex gap-2 flex-wrap">{PROJETO.professores.map((p) => (<span key={p} className="pill" style={{ background: "rgba(255,255,255,0.06)", color: "#cfd6e0" }}>{p}</span>))}</div></Card>

      <div className="text-muted text-center" style={{ fontSize: 10 }}>250 alunos por semana, 5 cidades. Equipe: Greice, Luigi, Tiago e Cleiton.</div>
    </div>
  );
}

const NAV = {
  atleta: [
    { id: "inicio", label: "Início", icon: Home },
    { id: "pessoa", label: "Pessoa", icon: Activity },
    { id: "chat", label: "Chat", icon: MessageCircle },
    { id: "treinos", label: "Treinos", icon: Video },
    { id: "ranking", label: "Ranking", icon: Trophy },
    { id: "caminho", label: "Caminho", icon: Compass },
  ],
  responsavel: [
    { id: "filho", label: "Meu filho", icon: User },
    { id: "ranking", label: "Ranking", icon: Trophy },
    { id: "privacidade", label: "Privacidade", icon: Shield },
  ],
  professor: [
    { id: "painel", label: "Painel", icon: BarChart3 },
    { id: "atletas", label: "Atletas", icon: Users },
    { id: "treino", label: "Treino", icon: Clock },
    { id: "chat", label: "Chat", icon: MessageCircle },
    { id: "ranking", label: "Ranking", icon: Trophy },
  ],
  recrutador: [
    { id: "buscar", label: "Buscar", icon: Search },
    { id: "ranking", label: "Ranking", icon: Trophy },
  ],
};
const ROLE_LABEL = { atleta: "Atleta", responsavel: "Responsável", professor: "Professor", recrutador: "Faculdade" };

/* ================================================================== */
/* APP                                                                 */
/* ================================================================== */

export default function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [role, setRole] = useState("atleta");
  const [sport] = useState("futebol");
  const [screen, setScreen] = useState("inicio");
  const [coachSel, setCoachSel] = useState(ATHLETES[0].id);
  const [ageOk, setAgeOk] = useState(false);
  const scrollRef = useRef(null);
  useEffect(() => { if (scrollRef.current) scrollRef.current.scrollTop = 0; }, [screen]);
  const [skillsMap, setSkillsMap] = useState(() => Object.fromEntries(ATHLETES.map((a) => [a.id, { ...a.skills }])));

  const athletes = useMemo(() => ATHLETES.map((a) => ({ ...a, skills: skillsMap[a.id] })), [skillsMap]);
  const sportAthletes = athletes.filter((a) => a.sport === sport);
  const activeAthlete = sportAthletes[0] || athletes[0];
  const accent = SPORTS[sport].accent;

  const handleLogin = (r) => { setRole(r); setScreen(NAV[r][0].id); setAgeOk(r !== "atleta"); setLoggedIn(true); };
  const me = role === "atleta" ? { name: activeAthlete.name, roleLabel: "Atleta" } : { name: "Prof. Ana", roleLabel: ROLE_LABEL[role] };

  const ranking = useMemo(() => {
    const base = sportAthletes.map((a) => ({ name: a.name, xp: a.xp, isYou: a.id === activeAthlete.id && (role === "atleta" || role === "responsavel") }));
    let i = 0;
    while (base.length < 11) { base.push({ name: FILLER_NAMES[i % FILLER_NAMES.length], xp: 2300 - base.length * 130 - i * 11, isYou: false }); i++; }
    base.sort((a, b) => b.xp - a.xp);
    return base.slice(0, 11).map((e, idx) => ({ ...e, rank: idx + 1 }));
  }, [sportAthletes, activeAthlete, role]);

  const renderScreen = () => {
    if (screen === "chat") return <ChatScreen me={me} accent={accent} />;
    if (screen === "ranking") return <RankingScreen ranking={ranking} accent={accent} sportLabel={SPORTS[sport].label} />;
    if (role === "atleta") {
      if (screen === "inicio") return <AthleteHome athlete={activeAthlete} />;
      if (screen === "pessoa") return <AthletePessoa athlete={activeAthlete} />;
      if (screen === "treinos") return <AthleteTraining athlete={activeAthlete} />;
      if (screen === "caminho") return <CaminhoScreen athlete={activeAthlete} />;
    }
    if (role === "responsavel") {
      if (screen === "filho") return <ParentChild athlete={activeAthlete} />;
      if (screen === "privacidade") return <ParentPrivacy athlete={activeAthlete} />;
    }
    if (role === "professor") {
      if (screen === "painel") return <CoachPanel />;
      if (screen === "atletas") return <CoachAthletes athletes={sportAthletes} onPick={(id) => { setCoachSel(id); setScreen("avaliar"); }} />;
      if (screen === "avaliar") return <CoachEvaluate athletes={sportAthletes} selId={coachSel} skillsMap={skillsMap} setSkillsMap={setSkillsMap} />;
      if (screen === "treino") return <CoachTraining />;
    }
    if (role === "recrutador" && screen === "buscar") return <RecruiterSearch athletes={athletes} />;
    return null;
  };

  if (!loggedIn) return (<div className="app" style={{ "--accent": "#22c55e" }}><style>{CSS}</style><LoginScreen onLogin={handleLogin} /></div>);
  if (role === "atleta" && !ageOk) return (<div className="app" style={{ "--accent": accent }}><style>{CSS}</style><AgeGate athlete={activeAthlete} onDone={() => setAgeOk(true)} /></div>);

  return (
    <div className="app" style={{ "--accent": accent }}>
      <style>{CSS}</style>
      <aside className="sidebar">
        <div className="sidebrand"><LogoMark size={34} /><div><div className="brand">RUMO À BOLSA</div><div className="text-muted" style={{ fontSize: 9, letterSpacing: 1.5 }}>{ROLE_LABEL[role].toUpperCase()}</div></div></div>
        <nav className="sidenav">{NAV[role].map((n) => { const Icon = n.icon, on = screen === n.id; return (<button key={n.id} onClick={() => setScreen(n.id)} className="sidenav-item" style={{ background: on ? `${accent}1a` : "transparent", color: on ? accent : "#9aa4b2" }}><Icon size={18} strokeWidth={on ? 2.4 : 2} /><span>{n.label}</span></button>); })}</nav>
        <button className="sidenav-item" style={{ color: "#9aa4b2", marginTop: "auto" }} onClick={() => setLoggedIn(false)}><LogOut size={18} /><span>Sair</span></button>
      </aside>
      <div className="appbody">
        <header className="topbar">
          <div className="flex items-center gap-2"><LogoMark size={34} /><div><div className="brand">RUMO À BOLSA</div><div className="text-muted" style={{ fontSize: 9, letterSpacing: 1.5 }}>{ROLE_LABEL[role].toUpperCase()}</div></div></div>
          <div className="flex items-center gap-2"><button className="iconbtn" onClick={() => setScreen("chat")} title="Conversas"><Bell size={16} /></button><button className="iconbtn topbar-logout" onClick={() => setLoggedIn(false)} title="Sair"><LogOut size={16} /></button></div>
        </header>
        <main className="main">{screen === "chat" ? <ChatScreen me={me} accent={accent} /> : <div className="scroll" ref={scrollRef}><div className="content">{renderScreen()}</div></div>}</main>
        <nav className="bottomnav">{NAV[role].map((n) => { const Icon = n.icon, on = screen === n.id; return (<button key={n.id} onClick={() => setScreen(n.id)} className="navitem" style={{ color: on ? accent : "#7b8696" }}><Icon size={19} strokeWidth={on ? 2.4 : 2} /><span style={{ fontWeight: on ? 700 : 500 }}>{n.label}</span></button>); })}</nav>
      </div>
    </div>
  );
}

